parameters.text:
Analiza el siguiente output del servidor VPS de AURENIX y determina su estado de salud.

OUTPUT DEL SERVIDOR:
{{ $node["SSH (Get Health)"].json["stdout"] }}

parameters.jsCode:
try {
  let raw = $node["Cerebro Inspector (Groq)"].json.text;
  if (raw.startsWith('```json')) raw = raw.substring(7, raw.length - 3);
  else if (raw.startsWith('```')) raw = raw.substring(3, raw.length - 3);
  const aiData = JSON.parse(raw.trim());
  return [{ json: aiData }];
} catch (e) {
  return [{ json: { status: "error_parseo", issues: ["Error parseando respuesta IA"], proposed_fix_command: "None", reason: e.message, raw: $node["Cerebro Inspector (Groq)"].json.text } }];
}

const text = $node["Telegram Trigger (HITL Receive)"].json.message.text;
const cmd = text.replace('/approve', '').trim();
if (!cmd) {
  throw new Error('No se especifico ningun comando despues de /approve');
}
return [{ json: { command_to_execute: cmd } }];

const cmd = $json.command_to_execute;

// Prefijos permitidos
const allowedPrefixes = [
  'docker ps', 'docker start', 'docker stop', 'docker restart',
  'docker logs', 'docker stats', 'docker inspect', 'docker exec',
  'free', 'df', 'uptime', 'top -bn1', 'ls', 'cat /var/log',
  'tail ', 'head ', 'systemctl status', 'systemctl restart',
  'journalctl', 'netstat', 'ss ', 'ip addr', 'ping ',
  'du -sh', 'find / -name', 'htop'
];

// Keywords bloqueados (destructivos)
const blockedKeywords = [
  'rm -rf', 'rm -f', 'rmdir', 'dd if=', 'mkfs',
  'shutdown', 'reboot', 'halt', 'poweroff', 'init 0',
  'chmod 777', 'chmod -R 777',
  'DROP ', 'DELETE FROM', 'TRUNCATE ',
  ':(){', 'fork', '> /dev/sda',
  'curl | bash', 'wget | bash',
  'passwd', 'useradd', 'userdel',
  'iptables -F', 'ufw disable'
];

const isAllowed = allowedPrefixes.some(p => cmd.startsWith(p));
const hasBlocked = blockedKeywords.some(k => cmd.toLowerCase().includes(k.toLowerCase()));

if (isAllowed && !hasBlocked) {
  return [{ json: { command_to_execute: cmd, safe: true } }];
} else {
  const reason = hasBlocked
    ? 'Comando contiene keyword destructivo: ' + blockedKeywords.find(k => cmd.toLowerCase().includes(k.toLowerCase()))
    : 'Comando no esta en la lista de permitidos';
  return [{ json: { command_to_execute: cmd, safe: false, reason: reason } }];
}

